// lib/products.js
import { unstable_cache } from 'next/cache';

import { getAllProducts } from './db.js';

// Keep the catalog cache in one shared accessor so every catalog view can use
// the same invalidation tag.
export const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['products'],
  { tags: ['products'] }
);


// app/page.tsx
import { revalidateTag } from 'next/cache';

import { getCachedProducts } from '../lib/products.js';

export default async function Page() {
  async function syncLatestCatalog() {
    'use server';

    revalidateTag('products', 'max');
  }

  const products = await getCachedProducts();

  return (
    <main>
      <header>
        <div>
          <p>Operations / Catalog</p>
          <h1>Product catalog</h1>
          <p>Browse current pricing, inventory, and availability.</p>
        </div>
        <form action={syncLatestCatalog}>
          <button type="submit">Sync latest catalog</button>
        </form>
      </header>

      <section aria-labelledby="products-heading">
        <div>
          <h2 id="products-heading">Products</h2>
          <p>{products.length} products</p>
        </div>
        <table>
          <thead>
            <tr>
              <th scope="col">Product</th>
              <th scope="col">Price</th>
            </tr>
          </thead>
          <tbody>
            {products.map(product => (
              <tr key={product.id}>
                <td>{product.name}</td>
                <td>${product.price.toFixed(2)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </main>
  );
}


